<template><section class="page"><div class="panel"><el-table :data="rows" v-loading="loading"><el-table-column prop="carrier_code" label="编码"/><el-table-column prop="carrier_name" label="名称"/><el-table-column prop="query_base_url" label="查询地址"/><el-table-column prop="enabled" label="启用"><template #default="s"><el-switch :model-value="s.row.enabled" disabled/></template></el-table-column></el-table><p class="muted">Webhook 密钥不会在前端明文展示。</p></div></section></template><script setup lang="ts">import { onMounted, ref } from 'vue'; import { http } from '../api/http'; const rows=ref<any[]>([]); const loading=ref(false); async function load(){loading.value=true; try{rows.value=await http.get('/carriers')} finally{loading.value=false}} onMounted(load)</script>
